/* ---------- RENDER GRID ---------- */
function displayVehicles(list) {
  const grid = document.getElementById("vehicleGrid");
  grid.innerHTML = "";
  if (!list || list.length === 0) {
    grid.innerHTML = `<div class="no-results">No vehicles found. Try adjusting your filters.</div>`;
    return;
  }

  list.forEach(v => {
    const card = document.createElement("article");
    card.className = "vehicle-card";

    // image
    const img = document.createElement("img");
    img.className = "card-image";
    img.src = v.images && v.images.length ? v.images[0] : "images/logo.jpg";
    img.alt = v.title;

    // availability badge
    const badge = document.createElement("div");
    badge.className = "availability " + (v.status === "available" ? "avail-available" : (v.status === "booked" ? "avail-booked" : "avail-sold"));
    badge.textContent = v.status === "available" ? "Available" : (v.status === "booked" ? "Booked" : "Sold");

    // body
    const body = document.createElement("div");
    body.className = "card-body";

    const title = document.createElement("div");
    title.className = "title";
    title.textContent = v.title;

    const meta = document.createElement("div");
    meta.className = "meta";
    meta.textContent = `${v.mileage} • ${v.engine}cc • ${v.transmission} • ${v.year}`;

    const price = document.createElement("div");
    price.className = "price";
    price.textContent = formatCurrency(v.price);

    // link to details page (new)
    const link = document.createElement("a");
    link.className = "card-link";
    link.href = `car-details.html?id=${encodeURIComponent(v.id)}`;
    link.setAttribute('aria-label', v.title);

    // compose
    body.appendChild(title);
    body.appendChild(meta);
    body.appendChild(price);

    card.appendChild(img);
    card.appendChild(badge);
    card.appendChild(body);
    card.appendChild(link);
    grid.appendChild(card);
  });
}

/* helper to format currency same as before */
function formatCurrency(n) {
  return "KSh " + n.toLocaleString();
}

/* ---------- init (make sure data.js is loaded before) ---------- */
document.addEventListener("DOMContentLoaded", () => {
  // window.allVehicles is from scripts/data.js
  displayVehicles(window.allVehicles);
});


























